/**
 * ╔══════════════════════════════════════════════════════════════════════╗
 * ║                        SOCIAL MANAGER                               ║
 * ║                     src/lib/SocialManager.ts                        ║
 * ║                                                                      ║
 * ║  Manages the in-game social layer. Stores feed posts and DM         ║
 * ║  threads generated by the DirectorAI. The /science/social page      ║
 * ║  reads from this manager — seed data is the fallback, live          ║
 * ║  DirectorAI posts are prepended and marked as LIVE.                 ║
 * ║                                                                      ║
 * ║  Storage: localStorage (client-side, persisted across sessions).    ║
 * ║  Max: 100 posts, 50 DMs per thread. FIFO eviction.                  ║
 * ╚══════════════════════════════════════════════════════════════════════╝
 */

import type { ArcId } from './GameEngine';

// ── Types ─────────────────────────────────────────────────────────────────────

export interface LiveFeedPost {
  id:           string;
  charId:       string;
  text:         string;
  tags:         string[];
  arcId:        ArcId;
  timestamp:    number;    // unix ms
  displayTime:  string;    // formatted "HH:MM · LOCATION · ACT I"
  likes:        number;
  source:       'live' | 'seed';  // 'live' = from DirectorAI, 'seed' = hardcoded
  triggerEvent: string;
}

export interface LiveDMMessage {
  id:        string;
  threadKey: string;
  from:      string;
  text:      string;
  ts:        string;       // display time "HH:MM"
  timestamp: number;       // unix ms for ordering
}

const MAX_POSTS   = 100;
const MAX_DMS     = 50;

// ── Location Labels by arc ─────────────────────────────────────────────────────

const ARC_LOCATIONS: Record<ArcId, string[]> = {
  'venus-protocol':    ['VENUS SURFACE', 'BASE CAMP ALPHA', 'PERIMETER LINE', 'CRASH SITE'],
  'forge-sequence':    ['SHIPYARD', 'FORGE BAY', 'TEST RANGE', 'COLONY DECK'],
  'breakout':          ['LAUNCH CORRIDOR', 'ORBIT APPROACH', 'ASTEROID BELT', 'TRANSIT'],
  'alliance-formation':['ALLIANCE ZERO HQ', 'NEXUS CORE', 'COMMAND BRIDGE', 'DEEP SPACE'],
};

function pickLocation(arcId: ArcId): string {
  const locations = ARC_LOCATIONS[arcId] ?? ['UNKNOWN SECTOR'];
  return locations[Math.floor(Math.random() * locations.length)];
}

function formatDisplayTime(arcId: ArcId): string {
  const now  = new Date();
  const hh   = now.getHours().toString().padStart(2, '0');
  const mm   = now.getMinutes().toString().padStart(2, '0');
  const loc  = pickLocation(arcId);
  const act  = arcId === 'venus-protocol' ? 'ACT I'
    : arcId === 'forge-sequence' ? 'ACT II'
    : arcId === 'breakout' ? 'ACT III'
    : 'ACT IV';
  return `${hh}:${mm} · ${loc} · ${act}`;
}

// ── SocialManager Class ────────────────────────────────────────────────────────

class SocialManagerCore {
  private static _instance: SocialManagerCore;
  private _feedPosts:    LiveFeedPost[] = [];
  private _dmMessages:   LiveDMMessage[] = [];
  private _loaded        = false;

  private constructor() {}

  static getInstance(): SocialManagerCore {
    if (!SocialManagerCore._instance) {
      SocialManagerCore._instance = new SocialManagerCore();
    }
    return SocialManagerCore._instance;
  }

  // ── Init ──────────────────────────────────────────────────────────────────

  load(): void {
    if (this._loaded || typeof window === 'undefined') return;
    this._feedPosts  = [];
    this._dmMessages = [];
    this._loaded = true;
  }

  // ── Feed ──────────────────────────────────────────────────────────────────

  /** Push a new live post from the DirectorAI */
  addPost(post: {
    charId:       string;
    text:         string;
    tags:         string[];
    arcId:        ArcId;
    triggerEvent: string;
  }): LiveFeedPost {
    this.load();
    const livePost: LiveFeedPost = {
      id:           `live_${Date.now()}_${Math.random().toString(36).slice(2, 5)}`,
      charId:       post.charId,
      text:         post.text,
      tags:         post.tags,
      arcId:        post.arcId,
      timestamp:    Date.now(),
      displayTime:  formatDisplayTime(post.arcId),
      likes:        Math.floor(Math.random() * 12) + 1, // seed likes
      source:       'live',
      triggerEvent: post.triggerEvent,
    };

    // Prepend (newest first)
    this._feedPosts.unshift(livePost);
    if (this._feedPosts.length > MAX_POSTS) {
      this._feedPosts = this._feedPosts.slice(0, MAX_POSTS);
    }

    this._persist();
    console.log(`[SocialManager] Post added from ${post.charId}: "${post.text.slice(0, 50)}..."`);
    return livePost;
  }

  /** Bulk-add posts from a DirectorAI decision (newest-first) */
  addPosts(posts: { charId: string; text: string; tags: string[]; arcId: ArcId; triggerEvent: string }[]): void {
    for (const p of posts) this.addPost(p);
  }

  /** Get all live posts (already newest-first). Caller merges with seed data. */
  getLivePosts(arcFilter?: ArcId): LiveFeedPost[] {
    this.load();
    if (!arcFilter) return [...this._feedPosts];
    return this._feedPosts.filter(p => p.arcId === arcFilter);
  }

  /** Returns the most recent post from a character */
  getLastPost(charId: string): LiveFeedPost | null {
    this.load();
    return this._feedPosts.find(p => p.charId === charId) ?? null;
  }

  // ── DMs ───────────────────────────────────────────────────────────────────

  /** Add a DM message to a thread */
  addDM(threadKey: string, from: string, text: string): LiveDMMessage {
    this.load();
    const now = new Date();
    const dm: LiveDMMessage = {
      id:        `dm_${Date.now()}_${Math.random().toString(36).slice(2, 5)}`,
      threadKey,
      from,
      text,
      ts:        `${now.getHours().toString().padStart(2,'0')}:${now.getMinutes().toString().padStart(2,'0')}`,
      timestamp: Date.now(),
    };
    this._dmMessages.push(dm);

    // Trim per thread
    const thread = this._dmMessages.filter(m => m.threadKey === threadKey);
    if (thread.length > MAX_DMS) {
      const oldest = thread.slice(0, thread.length - MAX_DMS);
      this._dmMessages = this._dmMessages.filter(m => !oldest.includes(m));
    }

    this._persist();
    return dm;
  }

  /** Get all DMs for a thread, sorted oldest-first for display */
  getDMThread(threadKey: string): LiveDMMessage[] {
    this.load();
    return this._dmMessages
      .filter(m => m.threadKey === threadKey)
      .sort((a, b) => a.timestamp - b.timestamp);
  }

  /** Add a tension-spike DM thread when bond threshold crosses */
  addTensionDMs(tensionLevel: number): void {
    const threadKey = 'howard_butterworth';
    if (tensionLevel >= 85) {
      this.addDM(threadKey, 'butterworth', 'I need to discuss the operational plan.');
      this.addDM(threadKey, 'howard', 'There is a plan.');
      this.addDM(threadKey, 'butterworth', 'Howard.');
      this.addDM(threadKey, 'howard', 'There is also a problem with the plan.');
      this.addDM(threadKey, 'butterworth', 'What is the problem.');
      this.addDM(threadKey, 'howard', 'The plan is the problem.');
    } else if (tensionLevel >= 70) {
      this.addDM(threadKey, 'butterworth', 'Are you alright.');
      this.addDM(threadKey, 'howard', 'Define alright.');
      this.addDM(threadKey, 'butterworth', 'Functional.');
      this.addDM(threadKey, 'howard', 'Then yes.');
    }
  }

  /** Add a match-result DM conversation between Howard and Butterworth */
  addMatchDMs(result: string, killsA: number, cargoA: number): void {
    const threadKey = 'howard_butterworth';
    if (result === 'perfectVictory') {
      this.addDM(threadKey, 'butterworth', 'That was decisive.');
      this.addDM(threadKey, 'howard', 'Yes.');
      this.addDM(threadKey, 'butterworth', 'Should I file a performance report.');
      this.addDM(threadKey, 'howard', 'No.');
      this.addDM(threadKey, 'butterworth', 'I already filed it.');
    } else if (result === 'win') {
      this.addDM(threadKey, 'butterworth', `Perimeter held. ${killsA} eliminations. Cargo intact.`);
      this.addDM(threadKey, 'howard', 'Good.');
    } else if (result === 'loss') {
      this.addDM(threadKey, 'butterworth', 'We lost the engagement.');
      this.addDM(threadKey, 'howard', 'I know.');
      this.addDM(threadKey, 'butterworth', 'Shall I draft a post-match assessment.');
      this.addDM(threadKey, 'howard', 'No.');
      this.addDM(threadKey, 'butterworth', 'I will draft a brief one.');
    } else if (result === 'draw') {
      this.addDM(threadKey, 'butterworth', 'Inconclusive result. Strategically neutral.');
      this.addDM(threadKey, 'howard', 'That is a complicated way to say we did not win.');
      this.addDM(threadKey, 'butterworth', 'Yes.');
    }
  }

  // ── Stats ─────────────────────────────────────────────────────────────────

  getPostCount(charId?: string): number {
    this.load();
    return charId
      ? this._feedPosts.filter(p => p.charId === charId).length
      : this._feedPosts.length;
  }

  getDMCount(threadKey: string): number {
    this.load();
    return this._dmMessages.filter(m => m.threadKey === threadKey).length;
  }

  hasLivePosts(): boolean {
    this.load();
    return this._feedPosts.some(p => p.source === 'live');
  }

  private _persist(): void {
    // REMOVED: localStorage usage per architectural rules. State is transient in-memory.
  }

  clearAll(): void {
    this._feedPosts = []; this._dmMessages = [];
    console.log('[SocialManager] All posts and DMs cleared.');
  }
}

// ── Export singleton ──────────────────────────────────────────────────────────

export const SocialManager = SocialManagerCore.getInstance();

/**
 * USAGE EXAMPLES
 * ──────────────────────────────────────────────────────────────────────
 *
 * // Add a DirectorAI post to the feed:
 * SocialManager.addPost({
 *   charId: 'howard', text: 'Made it to Venus. This was not the plan.',
 *   tags: ['#VenusProtocol'], arcId: 'venus-protocol', triggerEvent: 'venus_arrival'
 * });
 *
 * // Bulk-add from DirectorAI decision:
 * SocialManager.addPosts(DirectorAI.dequeueFeedPosts());
 *
 * // Read the live feed (merge with seed data on the social page):
 * const livePosts = SocialManager.getLivePosts();
 *
 * // Add match DMs automatically:
 * SocialManager.addMatchDMs('win', 3, 12);
 * // → Howard and Butterworth exchange messages about the result
 *
 * // Add tension DMs when bond threshold crossed:
 * SocialManager.addTensionDMs(85);
 */
